import{_ as e,o as a,c as i,ae as n}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Google Ads Overview","description":"","frontmatter":{"title":"Google Ads Overview","slug":"google-ads"},"headers":[],"relativePath":"marketer-hub/google-ads.md","filePath":"marketer-hub/google-ads.md"}'),o={name:"marketer-hub/google-ads.md"};function r(d,t,s,l,p,h){return a(),i("div",null,[...t[0]||(t[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch, as a Google App Attribution partner, offers advanced ad attribution analytics with Google Ads.</p><p>By combining Branch data with Google&#39;s self-attributing network (SAN) data, you can pinpoint the factors affecting user engagement and make informed decisions about app campaigns, leading to improved conversion rates.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><p>Branch integrates with Google Ads differently based on attribution methodology and campaign type:</p><h4 id="attribution-via-api" tabindex="-1">Attribution via API <a class="header-anchor" href="#attribution-via-api" aria-label="Permalink to &quot;Attribution via API&quot;">​</a></h4><ol><li><p>Branch connects with Google through a Mobile Measurement Partner (MMP) API Endpoint through account authentication in the Branch Dashboard.</p></li><li><p>Events are configured to send from Branch to Google.</p></li><li><p>Once campaigns are launched, users see an ad to download the app.</p></li><li><p>User installs the app and performs in-app events (ex. PURCHASE)</p><ul><li>The Branch SDK captures the app install and downstream events.</li></ul></li><li><p>Branch communicates with Google through the MMP API Endpoint and sends Google data about the conversion.</p></li><li><p>Google claims conversions by sending the click or impression campaign data that sourced it to Branch.</p></li><li><p>The Branch Dashboard will update reports for you to be able to compare and measure ad campaigns across platforms, ad set name, ad partner, etc.</p></li></ol><h4 id="attribution-via-branch-link" tabindex="-1">Attribution via Branch Link <a class="header-anchor" href="#attribution-via-branch-link" aria-label="Permalink to &quot;Attribution via Branch Link&quot;">​</a></h4><ol><li><p>Branch connects to Google using a Branch Ad Link. The Branch Ad Link is used in web engagement campaigns.</p></li><li><p>User sees a web-based ad and:</p><ul><li><p>If the app <strong>is not installed</strong>, get routed to the web</p></li><li><p>if the app <strong>is installed</strong>, get deep linked into the app</p><ul><li>iOS Universal Links or Android App Links must be configured in the <a href="https://support.google.com/google-ads/answer/6273460?hl=en" target="_blank" rel="noreferrer"><em>Final URL</em></a> field for the user to be redirected into the app. Branch Links can be configured in the Tracking Template field to enable attribution by Branch.</li></ul></li></ul></li><li><p>The Branch SDK captures conversion.</p></li><li><p>Google sends data to Branch through the use of the Branch Ad Link in the Tracking Template field.</p></li><li><p>The Branch Dashboard will update reports for you to be able to compare and measure ad campaigns across platforms, ad set name, ad partner, etc.</p></li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>Google will claim in-app conversions via the MMP API Endpoint if Universal/App Links (deep linking from the search ad to the app). Branch then pulls in all the campaign information.</p></div><h2 id="campaign-support" tabindex="-1">Campaign support <a class="header-anchor" href="#campaign-support" aria-label="Permalink to &quot;Campaign support&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Campaign type</th><th>Conversion support</th><th>Attribution framework</th><th>Deep linking support</th><th>Branch Link type</th><th>Branch Link placement</th></tr></thead><tbody><tr><td>App Promotion (ACi)</td><td>Installs &amp; In-App Events</td><td>via MMP API</td><td>- SAN deferred deep linking</td><td>N/A</td><td>N/A</td></tr><tr><td>App Promotion (ACe)</td><td>Opens &amp; In-app Events</td><td>via MMP API</td><td>- Universal Links - App Links - URI Scheme</td><td>N/A</td><td>N/A</td></tr><tr><td>Display, Discovery, Video, Shopping</td><td>Opens &amp; In-app Events</td><td>via Branch Link or MMP API</td><td>- Universal Links - App Links - URI Scheme</td><td>Display Ad Link</td><td>Campaign or Ad level tracking template (not in Final URL)</td></tr><tr><td>Search</td><td>Opens &amp; In-app Events</td><td>via Branch Link or MMP API</td><td>- Universal Links - App Links - URI Scheme</td><td>Search Ad Link</td><td>Campaign or Ad level tracking template (not in Final URL)</td></tr><tr><td>Performance Max</td><td>Web Events &amp; In-app Events</td><td>via Branch Link or MMP API</td><td>- Universal Links - App Links - URI Scheme</td><td>Display Ad Link</td><td>Campaign or Ad level tracking template</td></tr></tbody></table><p>Branch Ad Links are required for web event attribution. MMP API attribution is always considered for App events, even when Branch Ad Links are leveraged.</p><h3 id="campaign-identifiers" tabindex="-1">Campaign identifiers <a class="header-anchor" href="#campaign-identifiers" aria-label="Permalink to &quot;Campaign identifiers&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">Note</p><p>Please reach out to your Google Account Manager in order to <strong>add your app to the gBraid allowlist support</strong> and use the latest <a href="./ios-basic-integration.html">Branch iOS SDK</a>.</p></div><p>Google Ads has introduced several identifiers over time that are used for web-to-app attribution and attribution without device IDs.</p><table tabindex="0"><thead><tr><th></th><th>gBraid</th><th>GCLID (deeplink gclid)</th><th>GCLID (market_referrer_gclid)</th></tr></thead><tbody><tr><td><strong>Definition</strong></td><td>An aggregate click URL parameter that is forwarded back to Google on conversion events on <strong>iOS</strong> 14.5+ users that have not opted into app tracking.</td><td>A unique click URL parameter used to identify the campaign and other attributes of the click associated with the ad for ad tracking and campaign attribution.</td><td>A unique click URL parameter that is sourced from Google Play referrer at the time of app install and used for <strong>Android</strong> users that have opted out of ads personalization.</td></tr><tr><td><strong>Operating System</strong></td><td>iOS Only</td><td>iOS &amp; Android</td><td>Android Only</td></tr><tr><td><strong>Used for</strong></td><td>Re-engagements Only</td><td>Re-engagements Only</td><td>Installs Only</td></tr><tr><td><strong>Campaign Usage</strong></td><td>- Search - Shopping - Performance Max &amp; iOS ACi - Display and Youtube</td><td>App Engagement via all Google Ads campaigns</td><td>App Install via all Google Ads campaigns</td></tr></tbody></table><p>When Branch receives these identifiers and sends them in Google Ads Postbacks, Google Ads can utilize these identifiers for campaign optimizations.</p><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><h3 id="ios-attribution" tabindex="-1">iOS attribution <a class="header-anchor" href="#ios-attribution" aria-label="Permalink to &quot;iOS attribution&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Ad Type</th><th>Advertiser</th><th></th><th>SKAN</th></tr></thead><tbody><tr><td>Opt-In</td><td>Opt-Out</td><td></td><td></td></tr><tr><td>Web-Based</td><td><a href="./branch-methodology-overview.html">PREM</a> Attribution</td><td>None</td><td>✘</td></tr><tr><td>ACi</td><td><a href="./advertising-identifiers-for-attribution.html">IDFA</a> Attribution</td><td>None</td><td>✔</td></tr><tr><td>ACe</td><td><a href="./advertising-identifiers-for-attribution.html">IDFA</a> Attribution</td><td><a href="./google-ads.html#campaign-identifiers">GBRAID*</a></td><td>✘</td></tr></tbody></table><p>Due to changes in iOS policies, Google does not send iOS install attributions resulting from the following to any MMP:</p><ul><li><a href="https://support.google.com/google-ads/answer/9382304?hl=en" target="_blank" rel="noreferrer">Google Search channel/inventory</a></li><li>YouTube channel/inventory<br> While you can still view these attributions in your Google Ads account, you cannot view them in the Branch Dashboard as these modeled conversions will not be shared with Branch.</li></ul><p>For additional information on iOS 14 Impact on Google, visit the <a href="./ios-14-faqs.html">iOS 14 FAQs</a></p><p>For additional information on SKAdNetwork, visit our <a href="./google-skadnetwork.html">Google SKADNetwork guide</a>.</p><h3 id="deep-linking" tabindex="-1">Deep linking <a class="header-anchor" href="#deep-linking" aria-label="Permalink to &quot;Deep linking&quot;">​</a></h3><p>Deep linking support varies based on <a href="./google-ads.html#campaign-support">Campaign Type</a>.</p><p>For <strong>App Install Campaigns</strong>, Branch Links are not supported, and the only way to support deep linking is through Branch&#39;s <a href="./san-deferred-deep-linking.html"><strong>SAN Deferred Deep Linking</strong></a> feature.</p><p>For <strong>App Engagement Campaigns</strong>, Branch Links are not supported, so your developers are required to set up <a href="./ios-universal-links.html">iOS Universal Links</a>, <a href="./android-app-links.html">Android App Links</a>, and/or custom <a href="./in-app-routing.html">URI Scheme</a> to enable deep linking to in-app experiences.</p><p>For <strong>Web-based Ads</strong>, in order to enable deep linking, iOS Universal Links and Android App Links need to be enabled for your domain (the same domain entered into the campaign&#39;s <strong>Final URL</strong> field).</p>',30)])])}const u=e(o,[["render",r]]);export{g as __pageData,u as default};
